SELECT MAX(flow_mwh) AS max_flow_mwh
FROM energy_flow_data
WHERE energy_source_id = 1;

SELECT timestamp, flow_mwh
FROM energy_flow_data
ORDER BY timestamp DESC;

SELECT interface_name, timestamp, flow_mwh
FROM energy_flow_data
WHERE flow_id = 12345;

SELECT interface_name, AVG(latitude) AS average_latitude
FROM interfaces
GROUP BY interface_name;

SELECT timestamp, interface_name, flow_mwh
FROM energy_flow_data
ORDER BY timestamp DESC;
